+// ── Probe 11: API skeleton not in project root (Surface #18) ────────────
+
+#[test]
+fn probe_11_api_skeleton_relocated() {
+    assert!(
+        !Path::new("asupersync_v4_api_skeleton.rs").exists(),
+        "API skeleton still in project root"
+    );
