+        if let Ok(src) = fs::read_to_string(&file) {
+            assert!(
+                !src.contains("skeleton_placeholder!"),
+                "skeleton_placeholder! found in {}",
+                file.display()
+            );
+        }
+    }
+    eprintln!("[PASS] No skeleton_placeholder! in src/");
+}
